Here's a complete example:

**XAML**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    IsRefreshing="{Binding IsRefreshing}"
                    RemainingItemsThreshold="0">

        <CollectionView.Behaviors>
            <RefreshView Command="{Binding RefreshCommand}"
                         IsRefreshing="{Binding IsRefreshing}" />
        </CollectionView.Behaviors>

        <!-- Wrap in a RefreshView instead: -->
    </CollectionView>
</ContentPage>
```

The idiomatic approach is to **wrap** the `CollectionView` in a `RefreshView`:

```xml
<RefreshView Command="{Binding RefreshCommand}"
             IsRefreshing="{Binding IsRefreshing}">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}">
        <CollectionView.ItemTemplate>
            <DataTemplate>
                <Grid Padding="12" ColumnDefinitions="*,Auto">
                    <Label Text="{Binding Name}" FontSize="16" />
                    <Label Grid.Column="1" Text="›"
                           VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>

</RefreshView>
```

**ViewModel**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private bool _isRefreshing;

    private Item? _selectedItem;
    public Item? SelectedItem
    {
        get => _selectedItem;
        set
        {
            if (SetProperty(ref _selectedItem, value) && value is not null)
            {
                // Navigate, then clear selection so the user can re-select
                GoToDetailAsync(value).FireAndForget();
                SelectedItem = null;
            }
        }
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false;   // stops the spinner
        }
    }

    private async Task GoToDetailAsync(Item item)
    {
        await _nav.NavigateToAsync(nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = item });
    }
}
```

**Key bindings explained:**

| Binding | Purpose |
|---|---|
| `ItemsSource="{Binding Items}"` | Drives the list from an `ObservableCollection` |
| `SelectionMode="Single"` | Enables one-item selection |
| `SelectedItem="{Binding SelectedItem}"` | Two-way; setter triggers navigation then resets to `null` |
| `RefreshView.Command` | Fires `RefreshCommand` on pull-down |
| `RefreshView.IsRefreshing` | Two-way; set `false` in the VM to dismiss the spinner |

**Why reset `SelectedItem` to `null`?** Without it, tapping the same item a second time won't fire the setter again because the value hasn't changed.
